module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    // Internal signals
    wire [31:0] result;
    wire [32:0] temp_result;

    // Arithmetic and logic operations
    assign temp_result = (aluc == 6'b100000) ? {1'b0, a} + {1'b0, b} : // Add
                        (aluc == 6'b100010) ? {1'b0, a} - {1'b0, b} : // Subtract
                        (aluc == 6'b100100) ? {1'b0, a} & {1'b0, b} : // AND
                        (aluc == 6'b100101) ? {1'b0, a} | {1'b0, b} : // OR
                        (aluc == 6'b100110) ? {1'b0, a} ^ {1'b0, b} : // XOR
                        (aluc == 6'b100111) ? {1'b0, a} ~ {1'b0, b} : // NOR
                        (aluc == 6'b000000) ? {1'b0, a} << b : // Shift left
                        (aluc == 6'b000010) ? {1'b0, a} >> b : // Shift right
                        (aluc == 6'b000011) ? $signed(a) >>> b : // Shift right arithmetic
                        (aluc == 6'b000100) ? {a[31], a[31:1]} : // Rotate left
                        (aluc == 6'b000110) ? {a[0], a[31:1]} : // Rotate right
                        33'b0;

    assign result = temp_result[31:0];
    assign carry = temp_result[32];
    assign zero = (result == 32'b0);
    assign negative = (result[31] == 1'b1);
    assign overflow = (a[31] == b[31]) && (a[31] != result[31]);
    assign flag = overflow;

    assign r = result;

endmodule
